import { Link } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { toggleWishlist } from '../services/api';
import { toast } from 'react-toastify';

const Stars = ({ rating }) => '★'.repeat(Math.round(rating || 0)) + '☆'.repeat(5 - Math.round(rating || 0));

const ProductCard = ({ product }) => {
  const { addItem } = useCart();
  const { user } = useAuth();

  // Ensure this matches your Node.js server port
  const BACKEND_URL = "http://localhost:5000";

  const handleAddToCart = () => {
    addItem(product);
    toast.success('Added to cart!');
  };

  const handleWishlist = async () => {
    if (!user) return toast.info('Please login to save to wishlist');
    try {
      await toggleWishlist(product._id);
      toast.success('Wishlist updated!');
    } catch { 
      toast.error('Failed to update wishlist'); 
    }
  };

  /**
   * UNIVERSAL IMAGE FIX
   * This logic checks multiple possible database paths to find your image URL.
   */
  const getImageUrl = () => {
    // Try to find the first image URL in various formats
    const rawImg = 
      product.images?.[0]?.url ||   // Case 1: Array of objects [{url: '...'}]
      product.images?.[0] ||        // Case 2: Array of strings ['...', '...']
      product.image;                // Case 3: Single string field

    if (!rawImg || typeof rawImg !== 'string') {
      return `https://placeholder.com{encodeURIComponent(product.name)}`;
    }

    // If it's a full URL (Cloudinary), use it directly. 
    // Otherwise, prepend the backend URL for local uploads.
    if (rawImg.startsWith('http')) {
      return rawImg;
    } else {
      const separator = rawImg.startsWith('/') ? '' : '/';
      return `${BACKEND_URL}${separator}${rawImg}`;
    }
  };

  const img = getImageUrl();
  const price = product.discountPrice > 0 ? product.discountPrice : product.price;

  return (
    <div className="product-card">
      <div className="card-img-wrap">
        <Link to={`/products/${product._id}`}>
          <img 
            src={img} 
            alt={product.name} 
            loading="lazy" 
            onError={(e) => { e.target.src = `https://placeholder.com{product.name}`; }}
          />
        </Link>
        <button className="wishlist-btn" onClick={handleWishlist} title="Add to wishlist">♡</button>
        {product.discountPrice > 0 && (
          <span className="badge-sale">
            -{Math.round((1 - product.discountPrice / product.price) * 100)}%
          </span>
        )}
      </div>

      <div className="card-body">
        <p className="card-category">{product.category}</p>
        <Link to={`/products/${product._id}`}>
          <h3 className="card-title">{product.name}</h3>
        </Link>

        <div className="card-rating">
          <span className="stars"><Stars rating={product.rating} /></span>
          <span className="review-count">({product.numReviews || 0})</span>
        </div>

        <div className="card-price">
          <span className="price-current">PKR {price.toLocaleString()}</span>
          {product.discountPrice > 0 && (
            <span className="price-original">PKR {product.price.toLocaleString()}</span>
          )}
        </div>

        <button 
          className="btn-add-cart" 
          onClick={handleAddToCart} 
          disabled={product.stock === 0}
        >
          {product.stock === 0 ? 'Out of Stock' : 'Add to Cart'}
        </button>
      </div>
    </div>
  );
};

export default ProductCard;
